package com.trung.client;

import com.trung.dto.SalonDTO;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;
import org.springframework.web.client.RestTemplate;

@Component
public class SalonClient {
    @Autowired
    private RestTemplate restTemplate;

    private static final String SALON_SERVICE_URL = "http://SALON-SERVICE/api/salons";

    public SalonDTO getSalonById(Long salonId) throws Exception {
        try {
            SalonDTO salon = restTemplate.getForObject(SALON_SERVICE_URL + "/" + salonId, SalonDTO.class);
            if (salon == null) {
                throw new Exception("Salon not found with id: " + salonId);
            }
            return salon;
        } catch (Exception e) {
            throw new Exception("Failed to fetch salon data: " + e.getMessage());
        }
    }
}

package com.trung.client;

import com.trung.dto.ServiceDTO;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;
import org.springframework.web.client.RestTemplate;

import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

@Component
public class ServiceClient {
    @Autowired
    private RestTemplate restTemplate;

    private static final String SERVICE_OFFERING_URL = "http://SERVICE-OFFERING/api/service-offering";

    public Set<ServiceDTO> getServicesByIds(Set<Long> serviceIds) throws Exception {
        try {
            Set<ServiceDTO> services = new HashSet<>();
            for (Long serviceId : serviceIds) {
                ServiceDTO service = restTemplate.getForObject(SERVICE_OFFERING_URL + "/" + serviceId, ServiceDTO.class);
                if (service != null) {
                    services.add(service);
                }
            }
            return services;
        } catch (Exception e) {
            throw new Exception("Failed to fetch service data: " + e.getMessage());
        }
    }

    public ServiceDTO getServiceById(Long serviceId) throws Exception {
        try {
            ServiceDTO service = restTemplate.getForObject(SERVICE_OFFERING_URL + "/" + serviceId, ServiceDTO.class);
            if (service == null) {
                throw new Exception("Service not found with id: " + serviceId);
            }
            return service;
        } catch (Exception e) {
            throw new Exception("Failed to fetch service data: " + e.getMessage());
        }
    }
}

package com.trung.config;

import org.springframework.cloud.client.loadbalancer.LoadBalanced;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.client.RestTemplate;

@Configuration
public class RestTemplateConfig {

    @Bean
    @LoadBalanced
    public RestTemplate restTemplate() {
        return new RestTemplate();
    }
}
